1	const PROCESSING_FEE = 5;
2	const COMPONENT_BLOCK_SIZE = 3;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	const COMPONENT_TYPES = ["rune", "moonstone"];
5	const CURSE_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const LOYALTY_DISCOUNT_RATE = 0.2;
9	const LOYALTY_YEARS_THRESHOLD = 2;
10	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
11	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	type Item = { type: string; cursed?: boolean; enchantment?: number };
21	
22	const basePremiumFor = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];
23	
24	const isHighlyEnchanted = (item: Item): boolean =>
25	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
26	
27	const surchargeRate = (item: Item): number =>
28	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
29	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
30	
31	const mainItemPremium = (item: Item): number => {
32	  const base = basePremiumFor(item);
33	  return base + base * surchargeRate(item);
34	};
35	
36	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
37	
38	const componentGroupPremium = (group: Item[]): number =>
39	  group.length === COMPONENT_BLOCK_SIZE
40	    ? COMPONENT_BLOCK_PREMIUM
41	    : group.reduce((sum, item) => sum + basePremiumFor(item), 0);
42	
43	const groupComponentsByType = (items: Item[]): Item[][] => {
44	  const groups: Record<string, Item[]> = {};
45	  for (const item of items) {
46	    (groups[item.type] ||= []).push(item);
47	  }
48	  return Object.values(groups);
49	};
50	
51	type Customer = { yearsWithMHPCO: number };
52	
53	const loyaltyDiscountRate = (customer: Customer): number =>
54	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_DISCOUNT_RATE : 0;
55	
56	const itemsPremiumWithSurcharges = (items: Item[]): number => {
57	  const components = items.filter(isComponent);
58	  const mainItems = items.filter((item) => !isComponent(item));
59	  const mainTotal = mainItems.reduce((sum, item) => sum + mainItemPremium(item), 0);
60	  const componentTotal = groupComponentsByType(components).reduce(
61	    (sum, group) => sum + componentGroupPremium(group),
62	    0,
63	  );
64	  return mainTotal + componentTotal;
65	};
66	
67	const policyBasePremium = (items: Item[]): number => {
68	  const components = items.filter(isComponent);
69	  const mainItems = items.filter((item) => !isComponent(item));
70	  const mainBase = mainItems.reduce((sum, item) => sum + basePremiumFor(item), 0);
71	  const componentBase = groupComponentsByType(components).reduce(
72	    (sum, group) => sum + componentGroupPremium(group),
73	    0,
74	  );
75	  return mainBase + componentBase;
76	};
77	
78	export function quote(customer: Customer, items: Item[]): number {
79	  const itemsTotal = itemsPremiumWithSurcharges(items);
80	  const policyBase = policyBasePremium(items);
81	  const loyaltyDiscount = policyBase * loyaltyDiscountRate(customer);
82	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
83	  const total = itemsTotal - loyaltyDiscount + firstInsuranceSurcharge + PROCESSING_FEE;
84	  return Math.ceil(total);
85	}
86	
87	export function claim(): number {
88	  return undefined as unknown as number;
89	}
